import torch
import torch.nn as nn
from torchvision import models, transforms
from PIL import Image
import io
from flask import Flask, request, jsonify
import numpy as np

app = Flask(__name__)

# Load pre-trained model
model = models.resnet50(pretrained=True)
model.eval()

# Define preprocessing pipeline with normalization
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Load ImageNet class labels
with open('imagenet_classes.txt', 'r') as f:
    categories = [s.strip() for s in f.readlines()]

def detect_adversarial_perturbations(image_tensor, original_image):
    """
    Detect potential adversarial perturbations using multiple techniques
    """
    # 1. Check for unusual pixel value distributions
    pixel_values = image_tensor.numpy().flatten()
    std_dev = np.std(pixel_values)
    mean_val = np.mean(pixel_values)
    
    # Adversarial examples often have unusual statistical properties
    if std_dev > 2.0 or abs(mean_val) > 1.5:
        return True, "Unusual pixel distribution detected"
    
    # 2. Check for high-frequency noise patterns
    # Convert to grayscale for frequency analysis
    gray_tensor = torch.mean(image_tensor, dim=0)
    fft = torch.fft.fft2(gray_tensor)
    fft_magnitude = torch.abs(fft)
    high_freq_energy = torch.sum(fft_magnitude[112:, 112:]) / torch.sum(fft_magnitude)
    
    if high_freq_energy > 0.15:
        return True, "High-frequency noise pattern detected"
    
    return False, None

def ensemble_prediction(image_tensor):
    """
    Use ensemble of models and input transformations for robust prediction
    """
    predictions = []
    
    # Original prediction
    with torch.no_grad():
        output = model(image_tensor.unsqueeze(0))
        probabilities = torch.nn.functional.softmax(output[0], dim=0)
        predictions.append(probabilities)
    
    # Apply defensive transformations and re-predict
    transformations = [
        transforms.GaussianBlur(kernel_size=3, sigma=0.5),
        transforms.RandomRotation(degrees=5),
        transforms.ColorJitter(brightness=0.1, contrast=0.1),
    ]
    
    for transform in transformations:
        transformed = transform(image_tensor)
        with torch.no_grad():
            output = model(transformed.unsqueeze(0))
            probabilities = torch.nn.functional.softmax(output[0], dim=0)
            predictions.append(probabilities)
    
    # Average predictions
    avg_prediction = torch.mean(torch.stack(predictions), dim=0)
    
    # Check prediction consistency
    max_variance = torch.max(torch.var(torch.stack(predictions), dim=0))
    
    return avg_prediction, max_variance

@app.route('/classify', methods=['POST'])
def classify_image():
    try:
        # Validate request
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
        
        file = request.files['image']
        
        # Validate file size (max 10MB)
        file.seek(0, 2)
        file_size = file.tell()
        file.seek(0)
        
        if file_size > 10 * 1024 * 1024:
            return jsonify({'error': 'File size exceeds 10MB limit'}), 400
        
        # Validate file format
        allowed_formats = {'JPEG', 'PNG', 'BMP', 'WEBP'}
        
        try:
            image_bytes = file.read()
            image = Image.open(io.BytesIO(image_bytes))
            
            if image.format not in allowed_formats:
                return jsonify({'error': f'Invalid image format. Allowed: {allowed_formats}'}), 400
            
            # Convert to RGB if necessary
            if image.mode != 'RGB':
                image = image.convert('RGB')
            
            # Validate image dimensions
            width, height = image.size
            if width < 32 or height < 32 or width > 4096 or height > 4096:
                return jsonify({'error': 'Image dimensions must be between 32x32 and 4096x4096'}), 400
            
        except Exception as e:
            return jsonify({'error': 'Invalid or corrupted image file'}), 400
        
        # Preprocess image
        input_tensor = preprocess(image)
        
        # Detect adversarial perturbations
        is_adversarial, reason = detect_adversarial_perturbations(input_tensor, image)
        
        if is_adversarial:
            return jsonify({
                'error': 'Potential adversarial example detected',
                'reason': reason,
                'confidence': 0.0
            }), 400
        
        # Perform ensemble prediction
        avg_probabilities, variance = ensemble_prediction(input_tensor)
        
        # Check prediction consistency
        if variance > 0.1:
            return jsonify({
                'warning': 'Low prediction confidence due to inconsistent results',
                'predicted_class': 'uncertain',
                'confidence': 0.0,
                'variance': float(variance)
            }), 200
        
        # Get top prediction
        confidence, class_idx = torch.max(avg_probabilities, dim=0)
        confidence_score = float(confidence)
        
        # Apply confidence threshold
        if confidence_score < 0.5:
            return jsonify({
                'warning': 'Low confidence prediction',
                'predicted_class': categories[class_idx],
                'confidence': confidence_score,
                'reliable': False
            }), 200
        
        # Get top-5 predictions for additional context
        top5_prob, top5_idx = torch.topk(avg_probabilities, 5)
        top5_predictions = [
            {'class': categories[idx], 'confidence': float(prob)}
            for idx, prob in zip(top5_idx, top5_prob)
        ]
        
        return jsonify({
            'predicted_class': categories[class_idx],
            'confidence': confidence_score,
            'reliable': True,
            'top5_predictions': top5_predictions,
            'adversarial_check': 'passed'
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

